mapper.sql:
NOT EXISTS (
  SELECT 1
  FROM event_blocks eb_access
  WHERE eb_access.event_id = e.id
    AND eb_access.user_id = #{userId}
)

mapper.select:
SELECT , , CASE WHEN EXISTS ( SELECT 1 FROM event_blocks eb_me WHERE eb_me.event_id = e.id AND eb_me.user_id = #{userId} ) THEN 'blocked' ELSE ep.status END AS user_participant_status FROM events e LEFT JOIN event_participants ep ON ep.event_id = e.id AND ep.user_id = #{userId} WHERE AND AND
AND e.start_at >= #{from}
AND e.start_at < #{to}
AND ( e.title_hr ILIKE '%' || #{query} || '%' OR e.title_en ILIKE '%' || #{query} || '%' OR e.where_hr ILIKE '%' || #{query} || '%' OR e.where_en ILIKE '%' || #{query} || '%' OR e.address ILIKE '%' || #{query} || '%' OR e.about_hr ILIKE '%' || #{query} || '%' OR e.about_en ILIKE '%' || #{query} || '%' OR EXISTS ( SELECT 1 FROM event_tags et_query WHERE et_query.event_id = e.id AND et_query.tag ILIKE '%' || #{query} || '%' ) )
AND <= #{radiusKm}
ORDER BY
ASC,
COALESCE(e.start_at, e.when_iso) ASC, e.id ASC

SELECT , , CASE WHEN EXISTS ( SELECT 1 FROM event_blocks eb_me WHERE eb_me.event_id = e.id AND eb_me.user_id = #{userId} ) THEN 'blocked' ELSE ep.status END AS user_participant_status FROM events e LEFT JOIN event_participants ep ON ep.event_id = e.id AND ep.user_id = #{userId} WHERE (
e.creator_user_id = #{userId}
ep.status IN ('joined', 'approved', 'waitlisted', 'rejected') OR EXISTS ( SELECT 1 FROM event_blocks eb_user WHERE eb_user.event_id = e.id AND eb_user.user_id = #{userId} )
e.creator_user_id = #{userId} OR ep.status IN ('joined', 'approved', 'waitlisted', 'rejected') OR EXISTS ( SELECT 1 FROM event_blocks eb_user WHERE eb_user.event_id = e.id AND eb_user.user_id = #{userId} )
) AND ORDER BY e.start_at ASC

SELECT id, event_id, media_type, url, thumbnail_url, original_filename, storage_key, bucket_name, content_type, byte_size, width, height, sort_order FROM event_media WHERE event_id IN
#{eventId}
ORDER BY event_id ASC, sort_order ASC, created_at ASC

