mapper.update:
UPDATE events
SET organizer_rating_average = COALESCE((
      SELECT ROUND(AVG(rating)::NUMERIC, 2)
      FROM event_organizer_ratings
      WHERE event_id = #{eventId}
    ), 0),
    organizer_rating_count = (
      SELECT COUNT(*)::INTEGER
      FROM event_organizer_ratings
      WHERE event_id = #{eventId}
    ),
    updated_at = NOW()
WHERE id = #{eventId}

UPDATE events
SET event_rating_average = COALESCE((
      SELECT ROUND(AVG(rating)::NUMERIC, 2)
      FROM event_ratings
      WHERE event_id = #{eventId}
    ), 0),
    event_rating_count = (
      SELECT COUNT(*)::INTEGER
      FROM event_ratings
      WHERE event_id = #{eventId}
    ),
    updated_at = NOW()
WHERE id = #{eventId}
